class Solution {
public:
    int countBinarySubstrings(string s) {
        int count = 0;
        int n = s.length();
        for (int i = 0; i < n; i++) {
            int j = i;
            while (j < n && s[j] == s[i]) {
                j++;
            }
            count += (j - i);
        }
        return count;
    }
};
```

